import{c as e,k as a}from"./chunks/theme.C9g6HaIV.js";import{c as n,Q as r,j as s,m as o}from"./chunks/framework.BPKcPtvA.js";const f=JSON.parse('{"title":"Tenant Insights","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/tenant-insights.md","filePath":"guide/admin/tenant-insights.md","lastUpdated":1778912818000}'),i={name:"guide/admin/tenant-insights.md"};function l(d,t,h,g,c,m){return r(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="tenant-insights" tabindex="-1">Tenant Insights <a class="header-anchor" href="#tenant-insights" aria-label="Permalink to &quot;Tenant Insights&quot;">​</a></h1><p><strong>Tenant Insights</strong> is the fleet-wide analytics view. Where the <a href="./tenants">Tenants</a> page is for lifecycle operations, this page is for spotting usage patterns and problem tenants across the entire platform.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Top to bottom:</p><ol><li><strong>Filter bar</strong> — search, customer filter, instance filter, environment filter, status filter, date-range toggle (7d / 30d / 90d), and an optional <strong>Problem tenants only</strong> toggle in the summary card area.</li><li><strong>Summary cards</strong> — Total MAU, Avg Error Rate, Total Workflows, Problem Tenants count. Clicking the Problem Tenants card filters the grid to problem tenants only.</li><li><strong>Tenant grid</strong> — paginated, 24 cards per page, with a <strong>Load More</strong> button.</li></ol><p><img src="'+e+'" alt="Tenant Insights grid" class="light-only"><img src="'+a+'" alt="Tenant Insights grid" class="dark-only"></p><h2 id="tenant-insight-card" tabindex="-1">Tenant insight card <a class="header-anchor" href="#tenant-insight-card" aria-label="Permalink to &quot;Tenant insight card&quot;">​</a></h2><p>Each card represents one tenant.</p><ul><li><strong>Name</strong> with environment badge.</li><li><strong>Customer name</strong> in secondary text.</li><li>Four metric boxes: <strong>MAU</strong>, <strong>Avg DAU</strong>, <strong>Workflows</strong>, <strong>Error Rate</strong>.</li><li>A coloured border if the tenant is in trouble: red for error rate ≥ 1%, otherwise neutral.</li><li>A status dot in the corner (green / red / orange / grey).</li></ul><p>Click a card to jump to that tenant&#39;s detail page (Insights tab pre-selected).</p><h2 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Filter</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Search</strong></td><td>Tenant name match.</td></tr><tr><td><strong>Customer</strong></td><td>Single customer scope.</td></tr><tr><td><strong>Instance</strong></td><td>Single instance scope.</td></tr><tr><td><strong>Environment</strong></td><td>DEV / QA / UAT / etc.</td></tr><tr><td><strong>Status</strong></td><td>All / Active / Suspended / Provisioning / Archived.</td></tr><tr><td><strong>Date Range</strong></td><td>7d / 30d / 90d. Affects every metric on the page.</td></tr><tr><td><strong>Problem tenants</strong></td><td>Toggle in the summary cards. Shows only tenants where error rate ≥ 1%.</td></tr></tbody></table><h2 id="what-counts-as-a-problem-tenant" tabindex="-1">What counts as a &quot;problem tenant&quot;? <a class="header-anchor" href="#what-counts-as-a-problem-tenant" aria-label="Permalink to &quot;What counts as a &quot;problem tenant&quot;?&quot;">​</a></h2><p>A tenant is flagged as a problem when its <strong>average error rate</strong> in the selected date range is ≥ 1%. The metric is the same one shown on the card itself. There is no escalation or status change — the flag is informational.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Each card fetches its own metrics lazily as it scrolls into view. You will see brief spinners on freshly visible cards.</li><li>The page shows real data unless the <strong>Mock Data</strong> badge is visible in the header — that indicates a development feature flag, not real consumption.</li><li>Empty results show a friendly empty state with the active filter summary.</li></ul>',16)])])}const b=n(i,[["render",l]]);export{f as __pageData,b as default};
